import{_ as e,a,b as n,c as o,d as i}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as r,o as d,c as s,a2 as c}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Thêm OneDrive Channel","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/upload/onedrive.md","filePath":"vi-VN/upload/onedrive.md","lastUpdated":1781962217000}'),l={name:"vi-VN/upload/onedrive.md"};function p(h,t,m,u,g,b){return d(),s("div",null,[...t[0]||(t[0]=[c('<h1 id="them-onedrive-channel" tabindex="-1">Thêm OneDrive Channel <a class="header-anchor" href="#them-onedrive-channel" aria-label="Permalink to &quot;Thêm OneDrive Channel&quot;">​</a></h1><h2 id="can-chuan-bi-truoc" tabindex="-1">Cần chuẩn bị trước <a class="header-anchor" href="#can-chuan-bi-truoc" aria-label="Permalink to &quot;Cần chuẩn bị trước&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Vì sao cần</th></tr></thead><tbody><tr><td>Microsoft account</td><td>Dùng để access Microsoft admin pages và authorize OneDrive</td></tr><tr><td>ImgBed domain của bạn</td><td>Dùng cho OAuth callback URL</td></tr><tr><td>App registration</td><td>Dùng để generate <code>Client ID</code> và <code>Client Secret</code></td></tr><tr><td>OneDrive account</td><td>Dùng làm nơi lưu file thực tế</td></tr></tbody></table><h2 id="cac-buoc-thiet-lap" tabindex="-1">Các bước thiết lập <a class="header-anchor" href="#cac-buoc-thiet-lap" aria-label="Permalink to &quot;Các bước thiết lập&quot;">​</a></h2><h3 id="step-1-mo-microsoft-entra-id" tabindex="-1">Step 1: Mở Microsoft Entra ID <a class="header-anchor" href="#step-1-mo-microsoft-entra-id" aria-label="Permalink to &quot;Step 1: Mở Microsoft Entra ID&quot;">​</a></h3><ol><li>Mở <code>portal.azure.com</code>.</li><li>Tìm <code>Microsoft Entra ID</code> ở phía trên.</li><li>Nếu trang cần tìm không hiện trong dropdown, chọn:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Mở <code>Microsoft Entra ID</code>.</li><li>Mở <code>App registrations</code>.</li><li>Nhấn <code>New registration</code>.</li></ol><h3 id="step-2-register-app" tabindex="-1">Step 2: Register App <a class="header-anchor" href="#step-2-register-app" aria-label="Permalink to &quot;Step 2: Register App&quot;">​</a></h3><p>Trên trang <code>New registration</code>, điền:</p><table tabindex="0"><thead><tr><th>Field</th><th>Nhập gì</th></tr></thead><tbody><tr><td>Name</td><td>Tên dễ nhận biết, ví dụ <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Chọn theo bảng bên dưới</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Gợi ý chọn account type:</p><table tabindex="0"><thead><tr><th>Tình huống của bạn</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Chỉ dùng personal OneDrive</td><td>Chọn option cho personal Microsoft account.</td></tr><tr><td>Dùng cả personal và work/school accounts</td><td>Chọn option hỗ trợ cả personal và organizational accounts.</td></tr><tr><td>Chỉ dùng company hoặc school OneDrive</td><td>Chọn organizational account option.</td></tr></tbody></table><p>Điền xong thì nhấn register.</p><p><img src="'+e+'" alt="Create OneDrive app" loading="lazy"></p><h3 id="step-3-copy-app-information" tabindex="-1">Step 3: Copy App Information <a class="header-anchor" href="#step-3-copy-app-information" aria-label="Permalink to &quot;Step 3: Copy App Information&quot;">​</a></h3><p>Sau khi app được tạo, copy các giá trị này từ overview page:</p><table tabindex="0"><thead><tr><th>Microsoft Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> cho organizational accounts</td></tr></tbody></table><p><img src="'+a+'" alt="Application and tenant IDs" loading="lazy"></p><h3 id="step-4-tao-client-secret" tabindex="-1">Step 4: Tạo Client Secret <a class="header-anchor" href="#step-4-tao-client-secret" aria-label="Permalink to &quot;Step 4: Tạo Client Secret&quot;">​</a></h3><ol><li>Mở <code>Certificates &amp; secrets</code>.</li><li>Nhấn <code>New client secret</code>.</li><li>Nhập description tùy ý.</li><li>Chọn expiration period.</li><li>Copy <code>Value</code> ngay sau khi tạo.</li></ol><p><img src="'+n+'" alt="Save client secret value" loading="lazy"></p><h3 id="step-5-them-api-permissions" tabindex="-1">Step 5: Thêm API Permissions <a class="header-anchor" href="#step-5-them-api-permissions" aria-label="Permalink to &quot;Step 5: Thêm API Permissions&quot;">​</a></h3><ol><li>Mở <code>API permissions</code>.</li><li>Nhấn <code>Add a permission</code>.</li><li>Chọn <code>Microsoft Graph</code>.</li><li>Chọn <code>Delegated permissions</code>.</li><li>Thêm các permissions này:</li></ol><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Upload files, tạo folders và xóa files</td></tr><tr><td><code>offline_access</code></td><td>Cho phép ImgBed lấy <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Đọc account và quota information</td></tr></tbody></table><h3 id="step-6-đien-onedrive-channel" tabindex="-1">Step 6: Điền OneDrive Channel <a class="header-anchor" href="#step-6-đien-onedrive-channel" aria-label="Permalink to &quot;Step 6: Điền OneDrive Channel&quot;">​</a></h3><p>Trong Upload Settings, chọn <code>OneDrive</code> và điền:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>Nhập gì</th></tr></thead><tbody><tr><td>Channel name</td><td>Tên dễ nhận biết, ví dụ <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td><code>Client Secret Value</code> đã copy</td></tr><tr><td>Tenant ID</td><td>Dùng bảng bên dưới</td></tr><tr><td>Refresh Token</td><td>Tạm thời để trống</td></tr><tr><td>Root directory</td><td>Optional. Mặc định là <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Optional</td></tr></tbody></table><p><img src="'+o+'" alt="Fill OneDrive channel config" loading="lazy"></p><p>Cách điền <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Account Type You Chose</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Personal accounts</td><td><code>consumers</code></td></tr><tr><td>Personal + organizational accounts</td><td><code>common</code></td></tr><tr><td>Current organization only</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="step-7-lay-refresh-token" tabindex="-1">Step 7: Lấy Refresh Token <a class="header-anchor" href="#step-7-lay-refresh-token" aria-label="Permalink to &quot;Step 7: Lấy Refresh Token&quot;">​</a></h3><ol><li>Trong ImgBed, nhấn <code>Get Token</code>.</li><li>Sign in vào Microsoft account bạn muốn kết nối.</li><li>Approve authorization prompt.</li><li>Callback page sẽ hiển thị <code>Refresh Token</code>.</li><li>Copy token đó.</li><li>Quay lại ImgBed và paste vào field <code>Refresh Token</code>.</li></ol><p><img src="'+i+`" alt="Copy refresh token" loading="lazy"></p><h3 id="step-8-save-channel" tabindex="-1">Step 8: Save Channel <a class="header-anchor" href="#step-8-save-channel" aria-label="Permalink to &quot;Step 8: Save Channel&quot;">​</a></h3><p>Sau khi điền đủ fields, save channel.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mở portal.azure.com</span></span>
<span class="line"><span>-&gt; Tìm Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Mở App registrations</span></span>
<span class="line"><span>-&gt; Register app mới</span></span>
<span class="line"><span>-&gt; Điền Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Register</span></span>
<span class="line"><span>-&gt; Copy Application (client) ID</span></span>
<span class="line"><span>-&gt; Kiểm tra callback URL trong Authentication</span></span>
<span class="line"><span>-&gt; Tạo Client Secret trong Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Thêm permissions trong API permissions</span></span>
<span class="line"><span>-&gt; Điền Client ID / Client Secret / Tenant ID vào ImgBed</span></span>
<span class="line"><span>-&gt; Nhấn Get Token</span></span>
<span class="line"><span>-&gt; Copy Refresh Token từ callback page</span></span>
<span class="line"><span>-&gt; Paste lại vào ImgBed và save</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Microsoft Entra app registration: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const k=r(l,[["render",p]]);export{y as __pageData,k as default};
